diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..edebc0a40822 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2031,6 +2031,24 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
   }

+  {
+    // C3 - (and (sub nuw C1, X), C2) --> and X, (C2 & LowMask)
+    // where C2 is a negated power of 2 and C1 = C3 + (-C2) - 1.
+    // LowMask covers all bits up to the highest bit set in C1.
+    // Example: 64 - ((71 - X) & -8) --> X & 120
+    const APInt *C1, *C2, *C3;
+    Value *X;
+    if (match(Op1, m_OneUse(m_And(m_OneUse(m_NUWSub(m_APInt(C1), m_Value(X))),
+                                  m_APInt(C2)))) &&
+        C2->isNegatedPowerOf2() &&
+        match(Op0, m_APInt(C3)) && *C1 == *C3 - *C2 - 1) {
+      unsigned BW = I.getType()->getScalarSizeInBits();
+      APInt LowMask = APInt::getLowBitsSet(BW, C1->getActiveBits());
+      APInt NewMask = *C2 & LowMask;
+      return BinaryOperator::CreateAnd(X, ConstantInt::get(I.getType(), NewMask));
+    }
+  }
+
   const APInt *Op0C;
   if (match(Op0, m_APInt(Op0C)) && Op0C->isMask()) {
     // Turn this into a xor if LHS is 2^n-1 and the remaining bits are known
